sys_script_include.script:
const NavigationManager = Class.create();
NavigationManager.prototype = {
    initialize: function (page, params) {
        const that = this;

        const NAV_PREFIX = "scm_nav";

        this.page = page;
        this.params = params;
        this.navParams = {};

        Object.keys(params)
            .filter(
                (param) => param.startsWith(NAV_PREFIX) && param != NAV_PREFIX,
            )
            .forEach(
                (param) =>
                    (that.navParams[param.slice(NAV_PREFIX.length + 1)] =
                        params[param]),
            );
    },

    getConfigs: function () {
        const configs = this._getConfigsForPage();
        return configs;
    },

    _evaluateScript: function (grConfig, grCurrentRecord, scriptField) {
        const evaluator = new GlideScopedEvaluator();
        evaluator.putVariable("current", grCurrentRecord);
        evaluator.putVariable("navParams", this.navParams);

        const result = evaluator.evaluateScript(grConfig, scriptField);
        return result;
    },

    _getConfigsForPage: function () {
        const configs = [];
        const grConfig = new GlideRecord(
            Constants.NAVIGATION_MANAGER_CONFIG_TABLE,
        );
        grConfig.addQuery("page.id", this.page);
        grConfig.addQuery("active", true);
        grConfig.query();
        while (grConfig.next()) {
            let grCurrentRecord;

            if (grConfig.getValue("table")) {
                grCurrentRecord = new GlideRecord(
                    grConfig.getDisplayValue("table.name"),
                );
                grCurrentRecord.get(
                    grConfig.getValue("field_id"),
                    this.params[grConfig.getValue("param_id")],
                );
            }

            const title = grConfig.getValue("title");
            const options = grConfig.getValue("options");
            const beforeOpen = grConfig.getValue("before_open");
            let render = this._evaluateScript(
                grConfig,
                grCurrentRecord,
                "render_conditions",
            );
            render = render || {
                result: false,
                errorMessage:
                    'Navigation manager: could not evaluate the "Render condition" script due to an exception',
            };

            configs.push({
                title: title,
                options: options,
                render: render,
                beforeOpen: beforeOpen,
                widget_id: grConfig.getValue("widget_id"),
                name: grConfig.getValue("name"),
            });
        }
        return configs;
    },

    type: "NavigationManager",
};
